// --- Top Product Pairs inside Sold Combinations (robust) ---
let timeRange = 1h;
let startTime = now() - timeRange;

// Combinations that had at least one order in the window
let SoldCombos =
    orders
    | where event_time between (startTime .. now())
    | where isnotempty(combination_id)
    | summarize by combination_id;

// Build UNIQUE product list per sold combination (drop null/empty product_id)
let ItemsPerCombo =
    combination_items
    | where isnotempty(product_id)
    | join kind=inner SoldCombos on combination_id
    | summarize products = make_set(tostring(product_id)) by combination_id;

// Create unordered pairs (i1 < i2) within each combination, then count them
ItemsPerCombo
| mv-expand with_itemindex=i1 p1 = products to typeof(string)
| mv-expand with_itemindex=i2 p2 = products to typeof(string)
| where i1 < i2
| summarize Pair_Count = count() by Product_A = p1, Product_B = p2
| top 20 by Pair_Count desc

// --- Top 1 Product Pair inside Sold Combinations (with joined ID string) ---
let timeRange = 1h;
let startTime = now() - timeRange;

// Combinations that had at least one order in the window
let SoldCombos =
    orders
    | where event_time between (startTime .. now())
    | where isnotempty(combination_id)
    | summarize by combination_id;

// Build UNIQUE product list per sold combination (drop null/empty product_id)
let ItemsPerCombo =
    combination_items
    | where isnotempty(product_id)
    | join kind=inner SoldCombos on combination_id
    | summarize products = make_set(tostring(product_id)) by combination_id;

// Create unordered pairs (i1 < i2) within each combination, then count them
ItemsPerCombo
| mv-expand with_itemindex=i1 p1 = products to typeof(string)
| mv-expand with_itemindex=i2 p2 = products to typeof(string)
| where i1 < i2
| summarize Pair_Count = count() by Product_A = p1, Product_B = p2
| top 1 by Pair_Count desc
| extend Pair_Key = strcat(Product_A, " × ", Product_B)   // <-- joined string for Multi-Stat
| project Pair_Key, Product_A, Product_B, Pair_Count

// ===== Top 3 Product Pairs — CUMULATIVE Distinct Combinations per Minute (last hour) =====

// Parameters
let timeRange = 1h;
let startTime = now() - timeRange;
let step = 1m;

// Orders in window
let SoldOrders =
    orders
    | where event_time between (startTime .. now())
    | where isnotempty(combination_id)
    | project combination_id, event_time;

// Product sets per combination (static by combination_id)
let ItemsPerCombo =
    combination_items
    | where isnotempty(product_id)
    | summarize products = make_set(tostring(product_id)) by combination_id;

// All unordered pairs per combination
let PairsPerCombo =
    ItemsPerCombo
    | mv-expand with_itemindex=i1 p1 = products to typeof(string)
    | mv-expand with_itemindex=i2 p2 = products to typeof(string)
    | where i1 < i2
    | project combination_id, Product_A = p1, Product_B = p2, Pair_Key = strcat(p1, " × ", p2);

// Top 3 pairs in the last hour by distinct combinations that had ≥1 order
let TopPairs =
    PairsPerCombo
    | join kind=inner (SoldOrders | summarize by combination_id) on combination_id
    | summarize Pair_ComboCount = dcount(combination_id) by Product_A, Product_B
    | top 3 by Pair_ComboCount desc
    | extend Pair_Key = strcat(Product_A, " × ", Product_B)
    | project Pair_Key, Product_A, Product_B;

// Build a continuous per-minute series using make-series (non-cumulative)
let PerMinuteSeries =
    SoldOrders
    | join kind=inner PairsPerCombo on combination_id
    | join kind=inner TopPairs on Product_A, Product_B
    | make-series Combinations = dcount(combination_id) default=0
        on event_time from startTime to now() step step
        by Pair_Key;

// Convert to cumulative by expanding the arrays and taking row-wise cumsum per pair
PerMinuteSeries
| mv-apply ts = event_time to typeof(datetime), v = Combinations to typeof(long) on (
    order by ts asc
    | serialize
    | extend Cum = row_cumsum(v)
    | project event_time = ts, Pair_Key, Cum
)
| render timechart with (
    title = "Top 3 Product Pairs – CUMULATIVE Distinct Combinations per Minute (Last Hour)"
)
